    "高级": {
      "words": [["경어", "gyeongeo", "敬语", "경어는 중요합니다."], ["발표", "balpyo", "发表", "발표 준비를 합니다."], ["토론", "toron", "讨论", "토론을 나눕시다."], ["번역", "beonyeok", "翻译", "이 글을 번역해 주세요."], ["경험", "gyeongheom", "经验", "제 경험을 말씀드리겠습니다."], ["관점", "gwajeom", "视角", "다른 관점에서 생각해 봅시다."], ["의제", "uije", "议题", "오늘의 의제는 이것입니다."], ["결론", "gyeollon", "结论", "결론을 정리합니다."], ["근거", "geungeo", "根据", "그 의견에 근거가 있습니까?"], ["영향", "yeonghyang", "影响", "환경에 영향을 줍니다."], ["대응", "daeeung", "对应/处理", "신속하게 대응합니다."], ["조정", "jojung", "调整", "일정을 조정합니다."], ["검토", "geomto", "讨论/研究", "이 안을 검토합니다."], ["제안", "jean", "提案", "새로운 안을 제안합니다."], ["승낙", "seungnak", "承诺", "제안을 승낙합니다."], ["거절", "geojeol", "拒绝", "제안을 거절합니다."], ["상황", "sanghwang", "状况", "상황을 설명합니다."], ["배경", "baegyeong", "背景", "문제의 배경을 이해합니다."], ["과제", "gwaje", "课题", "큰 과제입니다."], ["목표", "mokpyo", "目标", "목표를 달성합니다."], ["전략", "jeollyak", "战略", "전략을 세웁니다."], ["효과", "hyogwa", "效果", "효과가 있습니다."], ["효율", "hyoyul", "效率", "효율적으로 일합니다."], ["품질", "pumjil", "质量", "품질을 중시합니다."], ["평가", "pyeongga", "评价", "성과를 평가합니다."]],
      "grammar": [["敬语 -시-", "用于抬高主语。", "선생님께서 오십니다.", "选择正确形式：사장님이 가___。", ['십니다', '습니다', '아요', '었어요']], ["间接引语", "다고 하다 表示转述。", "그는 바쁘다고 했어요.", "选择正确形式：비가 온___ 했어요。", ['다고', '라고', '고', '에게']], ["被动语态", "表示被做。", "비를 맞았어요.", "选择正确形式：이 책은 한강 작가에 의해 ___。", ['쓰였습니다', '썼습니다', '쓸 수 있습니다', '쓰게 했습니다']], ["使役态", "表示让/使某人做某事。", "아이에게 공부시켜요.", "选择正确形式：선생님은 학생에게 책을 ___。", ['읽게 합니다', '읽습니다', '읽힙니다', '읽을 수 있습니다']], ["条件表达对比", "면/다면/았/었으면 的区别。", "비가 오면 취소예요.", "选择正确形式：시간이___, 같이 갑시다。", ['있으면', '있다면', '있었으면', '있고']], ["-에 따라", "表示根据、随着。", "사람에 따라 의견이 달라요.", "选择正确形式：능력___ 일을 나눠요。", ['에 따라', '에 대해', '에 대해서', '에 관해']], ["-는 게 아니다", "表示并非。", "그 사람이 나쁜 게 아니에요.", "选择正确形式：비싸다고___ 맛있는 건 아니다。", ['해서', '는 게', '라서', '때문에']], ["-뿐만 아니라", "表示不仅…而且…。", "공부뿐만 아니라 운동도 해요.", "选择正确形式：이 가게는 낮___ 밤에도 열어요。", ['뿐만 아니라', '만', '밖에', '외에']], ["-를 통해", "表示通过。", "이 활동을 통해 많이 배웠어요.", "选择正确形式：인터넷___ 정보를 찾아요。", ['를 통해', '에 의해', '에 대해', '에 대하여']], ["-을 수밖에 없다", "表示不得不、只能。", "어쩔 수 없이 갈 수밖에 없어요.", "选择正确形式：시험이 다가와서 공부할___。", ['수밖에 없어요', ' 수 없어요', '수 있어요', '뿐이에요']]],
      "speaking": [["내일 짧은 발표를 하겠습니다.", "我明天会做一个简短演示。", "하겠습니다 是正式表达。"], ["오늘 시간 내 주셔서 감사합니다.", "感谢您今天抽出时间。", "商务敬语要放慢。"], ["제 관점에서 보면, 이 방안은 약간 문제가 있는 것 같습니다.", "从我的角度来看，这个方案有点问题。", "제 관점에서 表示观点。"], ["제안해 주신 내용에 대해 검토해 보겠습니다.", "关于您的提案，请允许我们研究一下。", "검토해 보겠습니다 表郑重。"], ["상황을 보면서 유연하게 대응해 나가야 합니다.", "需要一边观察情况一边灵活应对。", "～면서 同时进行。"], ["이 문제는 단순하지 않고, 다양한 요인이 얽혀 있습니다.", "这个问题不简单，各种因素交织在一起。", "다양한 各种各样的。"], ["목표를 달성하려면 팀 전체가 협력하는 게 중요합니다.", "为了达成目标，整个团队合作很重要。", "～려면 为了…。"], ["이번 경험을 통해 정말 많은 것을 배웠습니다.", "通过这次经验，真的学到了很多。", "～를 통해 通过…。"], ["각자의 입장에서 생각해 보는 게 중요합니다.", "站在各自的立场思考问题很重要。", "각자의 各自的。"], ["언어뿐만 아니라 문화와 배경도 이해하는 게 진정한 소통으로 이어집니다.", "不仅是语言，理解文化和背景才能带来真正的沟通。", "～뿐만 아니라 不仅…而且。"]],
      "listening": [["발표", "오늘은 제 언어 학습 경험에 대해 이야기하겠습니다. 언어를 배우는 건 단순히 단어와 문법을 외우는 게 아닙니다. 문화를 이해하는 것도 중요합니다.", "今天我将谈谈我的语言学习经验。学语言不只是背单词和语法，理解文化也很重要。"], ["문화", "언어는 단어와 문법만 있는 게 아닙니다. 문화도 담고 있어요. 한국어를 배우면서 한국 문화와 사고방식도 이해하게 됐어요.", "语言不只是词汇和语法，它也承载着文化。通过学韩语，我也理解了韩国文化和思维方式。"], ["비즈니스 회의", "그럼 오늘 의제로 넘어가겠습니다. 먼저 신제품 판매 전략에 대해 의견을 들려주세요.", "那我们进入今天的议题吧。首先，关于新产品的销售战略，请听听各位的意见。"], ["토론", "이 문제에 대해 다양한 의견이 있을 겁니다. 각자의 입장에서 토론하고, 최선의 결론을 내봅시다.", "关于这个问题，我想有各种各样的意见。让我们从各自的立场讨论，得出最好的结论。"], ["제안", "제가 제안 하나 드릴게요. 기존 시스템을 개선하는 것보다 새로운 시스템을 도입하는 게 장기적으로 더 효율적이라고 생각합니다.", "我有一个提案。与其改善现有系统，我认为导入新系统从长远来看更有效率。"], ["협상", "귀사의 제안을 검토해 봤는데, 가격 면에서 약간 조정이 필요할 것 같습니다. 10퍼센트만 내려주시면 검토해 보겠습니다.", "我们研究了贵公司的提案，认为价格方面需要调整。如果能下调10%，我们愿意考虑。"], ["강연", "언어의 다양성은 인류의 소중한 자산입니다. 하나하나의 언어에는 그것을 쓰는 사람들의 역사와 문화가 담겨 있습니다. 언어를 지키는 건 문화를 지키는 것과 연결됩니다.", "语言的多样性是人类的宝贵财产。每一种语言都承载着说它的人们的历史和文化。保护语言关系到保护文化。"]]
    }
